import React, { useEffect, useState, useRef } from "react";
import { MapContainer, TileLayer, CircleMarker, Tooltip } from "react-leaflet";
import "leaflet/dist/leaflet.css";

export default function BusMap() {
  const [buses, setBuses] = useState([]);
  const wsRef = useRef(null);

  const connectWS = () => {
    wsRef.current = new WebSocket("ws://127.0.0.1:8000/ws/buses");

    wsRef.current.onopen = () => console.log("[WS] Connected");
    wsRef.current.onclose = (e) => {
      console.log("[WS] Disconnected. Reconnecting in 3s...", e.reason);
      setTimeout(connectWS, 3000); // auto-reconnect
    };
    wsRef.current.onerror = (err) => {
      console.error("[WS] Error:", err.message);
      wsRef.current.close();
    };
    wsRef.current.onmessage = (event) => {
      try {
        const data = JSON.parse(event.data);

        // Merge Bronx + BQC buses
        const allBuses = [
          ...(data.Bronx || []),
          ...(data.BQC || [])
        ];

        // Define status: speed > 0 = Running, else Ghost
        const busesWithStatus = allBuses.map((b) => ({
          ...b,
          status: b.speed && b.speed > 0 ? "Running" : "Ghost"
        }));

        setBuses(busesWithStatus);
      } catch (err) {
        console.error("Failed to parse WS message:", err);
      }
    };
  };

  useEffect(() => {
    connectWS();

    return () => {
      if (wsRef.current) wsRef.current.close();
    };
  }, []);

  const runningCount = buses.filter((b) => b.status === "Running").length;
  const ghostCount = buses.filter((b) => b.status === "Ghost").length;

  return (
    <div style={{ height: "100vh", width: "100%", position: "relative" }}>
      {/* Running / Ghost overlay */}
      <div
        style={{
          position: "absolute",
          bottom: 10,
          left: 10,
          background: "rgba(255,255,255,0.9)",
          padding: "8px 12px",
          borderRadius: "8px",
          boxShadow: "0 2px 6px rgba(0,0,0,0.2)",
          zIndex: 1000,
          fontSize: "14px",
        }}
      >
        🟢 Running: {runningCount} <br />
        🔴 Ghost: {ghostCount}
      </div>

      <MapContainer
        center={[40.7128, -74.006]}
        zoom={12}
        style={{ height: "100%", width: "100%" }}
      >
        <TileLayer
          attribution='&copy; <a href="https://www.openstreetmap.org/">OpenStreetMap</a>'
          url="https://{s}.basemaps.cartocdn.com/light_all/{z}/{x}/{y}{r}.png"
          subdomains={["a", "b", "c", "d"]}
        />

        {buses.map((bus) => (
          <CircleMarker
            key={bus.id}
            center={[bus.lat, bus.lon]}
            radius={6}
            fillOpacity={1}
            color={bus.status === "Running" ? "green" : "red"}
          >
            <Tooltip>
              <div>
                <strong>Bus ID:</strong> {bus.id} <br />
                <strong>Route:</strong> {bus.route} <br />
                <strong>Status:</strong> {bus.status} <br />
                <strong>Speed:</strong> {bus.speed?.toFixed(1)} mph
              </div>
            </Tooltip>
          </CircleMarker>
        ))}
      </MapContainer>
    </div>
  );
}
